#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

struct Edge{
    int to;
    long long val;
};

bool operator<(Edge x,Edge y){
    return x.val>y.val;
}

int n,m,s;
long long dist[N];
vector<Edge> g[N];
priority_queue<Edge> q;
bool use[N];

int main(){
    scanf("%d%d%d",&n,&m,&s);
    for(int i=1;i<=m;i++){
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        g[u].push_back({v,w});
    }
    for(int i=1;i<=n;i++)
        dist[i]=(1LL<<31)-1;
    dist[s]=0;
    q.push({s,0});
    for(int tot=1;tot<=n;tot++){
        while(q.size() && use[q.top().to])
            q.pop();
        if(q.empty())
            break;
        int x=q.top().to,len=g[x].size();
        q.pop(),use[x]=1;
        for(int i=0;i<len;i++)
            if(dist[g[x][i].to]>(long long)dist[x]+g[x][i].val)
                dist[g[x][i].to]=dist[x]+g[x][i].val,q.push({g[x][i].to,dist[g[x][i].to]});
    }
    for(int i=1;i<=n;i++)
        printf("%lld ",dist[i]);
    return 0;
}
